using Microsoft.EntityFrameworkCore; using Restaurant.Data; using Restaurant.Services; var builder = WebApplication.CreateBuilder(args); builder.Services.AddControllers(); builder.Services.AddEndpointsApiExplorer(); builder.Services.AddSwaggerGen(); builder.Services.AddScoped<ReservationService>(); builder.Services.AddCors(opt => opt.AddPolicy("AllowAll", p => p.AllowAnyOrigin().AllowAnyMethod().AllowAnyHeader())); var conn = builder.Configuration.GetConnectionString("DefaultConnection"); builder.Services.AddDbContext<AppDbContext>(o => o.UseNpgsql(conn)); var app = builder.Build(); using (var scope = app.Services.CreateScope()) { var db = scope.ServiceProvider.GetRequiredService<AppDbContext>(); db.Database.Migrate(); } app.UseSwagger(); app.UseSwaggerUI(); app.UseCors("AllowAll"); app.UseStaticFiles(); app.MapControllers(); app.Run(); 
